function HashSet(s,u){var o=new Hashtable(s,u);this.add=function(n){o.put(n,!0)},this.addAll=function(n){for(var t=n.length;t--;)o.put(n[t],!0)},this.values=function(){return o.keys()},this.remove=function(n){return o.remove(n)?n:null},this.contains=function(n){return o.containsKey(n)},this.clear=function(){o.clear()},this.size=function(){return o.size()},this.isEmpty=function(){return o.isEmpty()},this.clone=function(){var n=new HashSet(s,u);return n.addAll(o.keys()),n},this.intersection=function(n){for(var t,e=new HashSet(s,u),i=n.values(),r=i.length;r--;)t=i[r],o.containsKey(t)&&e.add(t);return e},this.union=function(n){for(var t,e=this.clone(),i=n.values(),r=i.length;r--;)t=i[r],o.containsKey(t)||e.add(t);return e},this.isSubsetOf=function(n){for(var t=o.keys(),e=t.length;e--;)if(!n.contains(t[e]))return!1;return!0}}